    63→// capUpdateManagers merges a number of the oldest update entries into versioned buckets,
    64→// such that the number of entries from updates does not exceed f.maxUpdateManagers.
    65→func (f *capManagersManager) capUpdateManagers(managed Managed) (newManaged Managed, err error) {
    66→	// Gather all entries from updates
    67→	updaters := []string{}
    68→	for manager, fields := range managed.Fields() {
