    26→
    27→// Conflict is a conflict on a specific field with the current manager of
    28→// that field. It does implement the error interface so that it can be
    29→// used as an error.
    30→type Conflict struct {
    31→	Manager string
    32→	Path    fieldpath.Path
    33→}
    34→
    35→// Conflict is an error.
    36→var _ error = Conflict{}
    37→
    38→// Error formats the conflict as an error.
    39→func (c Conflict) Error() string {
    40→	return fmt.Sprintf("conflict with %q: %v", c.Manager, c.Path)
    41→}
    42→
    43→// Equals returns true if c == c2
    44→func (c Conflict) Equals(c2 Conflict) bool {
    45→	if c.Manager != c2.Manager {
    46→		return false
    47→	}
    48→	return c.Path.Equals(c2.Path)
    49→}
    50→
    51→// Conflicts accumulates multiple conflicts and aggregates them by managers.
    52→type Conflicts []Conflict
    53→
    54→var _ error = Conflicts{}
    55→
    56→// Error prints the list of conflicts, grouped by sorted managers.
    57→func (conflicts Conflicts) Error() string {
    58→	if len(conflicts) == 1 {
    59→		return conflicts[0].Error()
    60→	}
    61→
    62→	m := map[string][]fieldpath.Path{}
    63→	for _, conflict := range conflicts {
    64→		m[conflict.Manager] = append(m[conflict.Manager], conflict.Path)
    65→	}
    66→
    67→	managers := []string{}
    68→	for manager := range m {
    69→		managers = append(managers, manager)
    70→	}
    71→
    72→	// Print conflicts by sorted managers.
    73→	sort.Strings(managers)
    74→
    75→	messages := []string{}
    76→	for _, manager := range managers {
    77→		messages = append(messages, fmt.Sprintf("conflicts with %q:", manager))
    78→		for _, path := range m[manager] {
    79→			messages = append(messages, fmt.Sprintf("- %v", path))
    80→		}
    81→	}
    82→	return strings.Join(messages, "\n")
    83→}
    84→
    85→// Equals returns true if the lists of conflicts are the same.
    86→func (c Conflicts) Equals(c2 Conflicts) bool {
    87→	if len(c) != len(c2) {
    88→		return false
    89→	}
    90→	for i := range c {
    91→		if !c[i].Equals(c2[i]) {
    92→			return false
    93→		}
    94→	}
    95→	return true
    96→}
    97→
    98→// ToSet aggregates conflicts for all managers into a single Set.
    99→func (c Conflicts) ToSet() *fieldpath.Set {
   100→	set := fieldpath.NewSet()
   101→	for _, conflict := range []Conflict(c) {
   102→		set.Insert(conflict.Path)
   103→	}
   104→	return set
   105→}
   106→
   107→// ConflictsFromManagers creates a list of conflicts given Managers sets.
   108→func ConflictsFromManagers(sets fieldpath.ManagedFields) Conflicts {
   109→	conflicts := []Conflict{}
   110→
   111→	for manager, set := range sets {
   112→		set.Set().Iterate(func(p fieldpath.Path) {
   113→			conflicts = append(conflicts, Conflict{
   114→				Manager: manager,
   115→				Path:    p.Copy(),
   116→			})
   117→		})
   118→	}
   119→
   120→	return conflicts
   121→}
